// Step 1: Get upload URL
const response = await fetch('https://api.post-bridge.com/v1/media/create-upload-url', {
  method: 'POST',
  headers: { 'Authorization': 'Bearer YOUR_API_KEY', 'Content-Type': 'application/json' },
  body: JSON.stringify({ mime_type: 'image/jpeg', size_bytes: file.size, name: 'photo.jpg' })
});
const { media_id, upload_url } = await response.json();

// Step 2: Upload file
await fetch(upload_url, { method: 'PUT', headers: { 'Content-Type': 'image/jpeg' }, body: file });

const response = await fetch('https://api.post-bridge.com/v1/posts', {
  method: 'POST',
  headers: { 'Authorization': 'Bearer YOUR_API_KEY', 'Content-Type': 'application/json' },
  body: JSON.stringify({
    caption: 'Hello world!',
    social_accounts: [123, 456],
    media: ['media_id'],
    scheduled_at: '2024-12-31T12:00:00Z'
  })
});
const post = await response.json();

const response = await fetch('https://api.post-bridge.com/v1/posts/POST_ID', {
  method: 'PATCH',
  headers: { 'Authorization': 'Bearer YOUR_API_KEY', 'Content-Type': 'application/json' },
  body: JSON.stringify({ caption: 'Updated caption', scheduled_at: '2024-12-31T12:00:00Z' })
});
const updated = await response.json();

const response = await fetch('https://api.post-bridge.com/v1/social-accounts?platform=facebook&platform=instagram', { method: 'GET', headers: { 'Authorization': 'Bearer YOUR_API_KEY' } });
const accounts = await response.json();
const accountIds = accounts.data.map(acc => acc.id);
